import React, { useState, useMemo, useEffect } from "react";
import StickyBox from "react-sticky-box";
import IMG01 from "../../../assets/images/patient.jpg";
import DashboardSidebar from "../sidebar/sidebar.jsx";
import { Field, Form } from "react-final-form";
import { InputField } from "../../../../common/InputText";
import AlertDismissible from "../../../../common/AlertDismissible";
// import { Country, City } from "country-state-city";
import CountryCity from '../../../../common/Country-City'
import UserService from "../../../services/user.service";
import CircularProgress from "@mui/material/CircularProgress";
import { Error, required } from "../../../../common/Utilitis";
import { useTranslation } from "react-i18next";
function Profile(props) {
  const [t, i18n] = useTranslation();
  const [isLoading, setIsLoading] = useState(false);
  const [gettingUser, setGettingUser] = useState(true);
  const [currentUser, setCurrentUser] = useState(null);
  const [message, setMessage] = useState();
  const [profileUpdate, setProfileUpdate] = useState(false);
  const [selectedCountry, setSelectedCountry] = useState("JO");
  const sleep = (ms) => new Promise((resolve) => setTimeout(resolve, ms));

  useEffect(async () => {
    const response = await UserService.getCurrentUser();
    console.log(
      `Profile :: useEffect :: response?.body: ${JSON.stringify(response)}`
    );
    setCurrentUser(response?.body);
    setSelectedCountry(response?.body?.countryOfResidence);
    setGettingUser(false);
  }, []);

  const onSubmit = async (values) => {
    setProfileUpdate(false);
    console.log(`onSubmit :: ${JSON.stringify(values, 0, 2)}`);
    setIsLoading(true);
    // await sleep(1500);
    // calling update profile API
    const userData = {
      firstName: values.firstName,
      lastName: values.lastName,
      dateOfBirth: values.dateOfBirth,
      phone: values.phone,
      gender: values.gender,
      nationality: values.nationality,
      countryOfResidence: values.countryOfResidence,
      cityOfResidence: values.cityOfResidence,
    };
    const response = await UserService.updateUser(userData);
    setIsLoading(false);
    if (!!!response.success && !response.success) {
      setMessage(!!response.message && response.message);
      return;
    }
    setProfileUpdate(true);
  };
  const validate = async (values) => {
    const errors = {};
    if (!values.firstName) {
      errors.firstName = required;
    }
    if (!values.lastName) {
      errors.lastName = required;
    }
    if (!values.email) {
      errors.email = required;
    } else if (
      !values.email
        .toLowerCase()
        .match(
          /^(([^<>()[\]\\.,;:\s@"]+(\.[^<>()[\]\\.,;:\s@"]+)*)|(".+"))@((\[[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\.[0-9]{1,3}\])|(([a-zA-Z\-0-9]+\.)+[a-zA-Z]{2,}))$/
        )
    ) {
      errors.email = "Invalid Email format!";
    }
    if (!values.phone) {
      errors.phone = required;
    }
    if (!values.gender) {
      errors.gender = required;
    }
    if (!values.dateOfBirth) {
      errors.dateOfBirth = required;
    }
    if (!values.nationality) {
      errors.nationality = required;
    }
    if (!values.countryOfResidence) {
      errors.countryOfResidence = required;
    }
    if (!values.cityOfResidence) {
      errors.cityOfResidence = required;
    }
    return errors;
  };
  const optionsCountryList = useMemo(() => CountryCity.getCountriesList(), []);

  let profileForm = (
    <Form
      validate={validate}
      onSubmit={onSubmit}
      initialValues={{
        firstName: currentUser?.firstName,
        lastName: currentUser?.lastName,
        dateOfBirth: currentUser?.dateOfBirth?.split("T")[0],
        email: currentUser?.email,
        phone: currentUser?.phone,
        gender: currentUser?.gender,
        nationality: currentUser?.nationality,
        countryOfResidence: currentUser?.countryOfResidence,
        cityOfResidence: currentUser?.cityOfResidence,
      }}
      render={({
        handleSubmit,
        onChange,
        submitError,
        form,
        submitting,
        pristine,
        values,
      }) => (
        <form onSubmit={handleSubmit} className="needs-validation" noValidate>
          {message?.map((m, i) => (
            <div key={i} className="invalid-feedback d-block mb-2">
              {m}
            </div>
          ))}
          <div className="row form-row">
            {/* <div className="col-12 col-md-12">
        <div className="form-group">
          <div className="change-avatar">
            <div className="profile-img">
              <img src={IMG01} alt="User" />
            </div>
            <div className="upload-img">
              <div className="change-photo-btn">
                <span>
                  <i className="fa fa-upload"></i> Upload
                  Photo
                </span>
                <input type="file" className="upload" />
              </div>
              <small className="form-text text-muted">
                Allowed JPG, GIF or PNG. Max size of 2MB
              </small>
            </div>
          </div>
        </div>
      </div> */}
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.FirstName')}</label>
                {/* <input
              type="text"
              className="form-control"
              defaultValue="Richard"
            /> */}
                <Field
                  name="firstName"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.LastName')}</label>
                {/* <input
              type="text"
              className="form-control"
              defaultValue="Wilson"
            /> */}
                <Field
                  name="lastName"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.DateOfBirth')}</label>
                <div className="">
                  {/* <input
                type="text"
                className="form-control datetimepicker"
                defaultValue="24-07-1983"
              /> */}
                  <Field
                    name="dateOfBirth"
                    className="form-control floating datetimepicker"
                    type="date"
                    component={InputField}
                  />
                </div>
              </div>
            </div>
            {/* <div className="col-12 col-md-6">
        <div className="form-group">
          <label>Blood Group</label>
          <select className="form-control select">
            <option>A-</option>
            <option>A+</option>
            <option>B-</option>
            <option>B+</option>
            <option>AB-</option>
            <option>AB+</option>
            <option>O-</option>
            <option>O+</option>
          </select>
        </div>
      </div> */}
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.EmailID')}</label>
                {/* <input
              type="email"
              className="form-control"
              defaultValue="richard@example.com"
            /> */}
                <Field
                  name="email"
                  className="form-control floating"
                  type="email"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.Mobile')}</label>
                {/* <input
              type="text"
              defaultValue="+1 202-555-0125"
              className="form-control"
            /> */}
                <Field
                  name="phone"
                  className="form-control floating"
                  type="text"
                  component={InputField}
                />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.Gender')}</label>
                <div className="col-md-10">
                  <div className="radio">
                    {/* <input
                  id="male_radio"
                  name="gender"
                  value="male"
                  type="radio"
                /> */}

                    <Field
                      id="male_radio"
                      name="gender"
                      value="Male"
                      type="radio"
                      component={InputField}
                      hideerror="true"
                    />
                    <label htmlFor="male_radio">{t('ProfileForm.Male')}</label>
                  </div>
                  <div className="radio">
                    {/* <input
                  id="female_radio"
                  name="gender"
                  value="Female"
                  type="radio"
                />*/}
                    <Field
                      id="male_radio"
                      name="gender"
                      value="Female"
                      type="radio"
                      component={InputField}
                      hideerror="true"
                    />
                    <label htmlFor="female_radio">{t('ProfileForm.Female')}</label>
                  </div>
                  <Error name={"gender"} showerrorbeside="true" />
                </div>
              </div>
            </div>
            {/* <div className="col-12">
        <div className="form-group">
          <label>Address</label>
          <input
            type="text"
            className="form-control"
            defaultValue="806 Twin Willow Lane"
          />
        </div>
      </div> */}
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.Nationality')}</label>
                <Field name="nationality" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        defaultValue={values.nationality}
                        {...input.select}
                          onChange={(e) => {
                          input.onChange(e); //final-form's onChange
                        }}
                      >
                        <option value="">{t('ProfileForm.SelectNationality')}</option>
                        {optionsCountryList.map((val, index) => (
                          <option key={index} value={val.isoCode}>
                            {val.name}
                          </option>
                        ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"nationality"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.Country')}</label>
                <Field name="countryOfResidence" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        defaultValue={values.countryOfResidence}
                        {...input.select}
                        onChange={(e) => {
                          input.onChange(e); //final-form's onChange
                          setSelectedCountry(e.target.value);
                          //console.table(City.getCitiesOfCountry(e.target.value))
                        }}
                      >
                        <option value="">{t('ProfileForm.SelectCountry')}</option>
                        {optionsCountryList.map((val, index) => (
                          <option key={index} value={val.isoCode}>
                            {val.name}
                          </option>
                        ))}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"countryOfResidence"} showerrorbeside="true" />
              </div>
            </div>
            <div className="col-12 col-md-6">
              <div className="form-group">
                <label>{t('ProfileForm.City')}</label>
                <Field name="cityOfResidence" showerrorbeside="true">
                  {({ input, meta }) => {
                    return (
                      <select
                        className="form-control select"
                        defaultValue={values.cityOfResidence}
                        {...input.select}
                        onChange={(e) => {
                          input.onChange(e); //final-form's onChange
                        }}
                      >
                        <option value="">{t('ProfileForm.SelectCity')}</option>
                        {CountryCity.getCitiesOfCountry(selectedCountry).map(
                          (val, index) => (
                            <option key={index} value={val.name}>
                              {val.name}
                            </option>
                          )
                        )}
                      </select>
                    );
                  }}
                </Field>
                <Error name={"cityOfResidence"} showerrorbeside="true" />
              </div>
            </div>
          </div>

          {/* <div className="col-12 col-md-6">
        <div className="form-group">
          <label>State</label>
          <input
            type="text"
            className="form-control"
            defaultValue="Newyork"
          />
        </div>
      </div>
      <div className="col-12 col-md-6">
        <div className="form-group">
          <label>Zip Code</label>
          <input
            type="text"
            className="form-control"
            defaultValue="13420"
          />
        </div>
      </div> */}

          <div className="submit-section">
            <button
              type="submit"
              className="btn btn-primary submit-btn"
              disabled={isLoading}
            >
              {!isLoading ? t('ProfileForm.SaveChanges') : ""}
              {isLoading && (
                <span className="spinner-border spinner-border-sm mb-1"></span>
              )}
            </button>
          </div>
        </form>
      )}
    />
  );

  return (
    <div>
      <div className="content">
        <div className="container-fluid">
          <div className="row">
            <div className="col-md-5 col-lg-4 col-xl-3 theiaStickySidebar">
              <StickyBox offsetTop={20} offsetBottom={20}>
                <DashboardSidebar />
              </StickyBox>
            </div>

            <div className="col-md-7 col-lg-8 col-xl-9">
              <div className="card">
                <div className="card-body">
                  {profileUpdate ? (
                    <AlertDismissible
                      type={"success"}
                      boldMsg={"Success!"}
                      msg={"User have been updated successfully!"}
                    />
                  ) : (
                    ""
                  )}
                  {gettingUser ? (
                    <div className="centered">
                      <CircularProgress />
                    </div>
                  ) : (
                    profileForm
                  )}
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
export default Profile;
